// Validate and normalise the invoice payload before sending it to Claude.
const body = $json.body || {};
const client = (body.client || '').trim();
const clientEmail = (body.clientEmail || '').trim();
const services = Array.isArray(body.services) ? body.services : [];

if (!client) throw new Error('Missing client name');
if (!clientEmail) throw new Error('Missing client email');
if (services.length === 0) throw new Error('At least one service line item is required');

const lineItems = services
  .map(s => ({
    description: String(s.description || '').trim(),
    amount: Number(s.amount || 0),
  }))
  .filter(s => s.description && s.amount > 0);

if (lineItems.length === 0) throw new Error('No valid line items provided');

const subtotal = lineItems.reduce((sum, l) => sum + l.amount, 0);
const gst = Math.round(subtotal * 0.10 * 100) / 100;
const total = Math.round((subtotal + gst) * 100) / 100;

const now = new Date();
const pad = (n) => String(n).padStart(2, '0');
const dateStr = `${now.getFullYear()}-${pad(now.getMonth() + 1)}-${pad(now.getDate())}`;
const invoiceNumber = `INV-${now.getFullYear()}${pad(now.getMonth()+1)}${pad(now.getDate())}-${String(now.getTime()).slice(-4)}`;

return [{
  json: {
    client,
    clientEmail,
    lineItems,
    subtotal,
    gst,
    total,
    dateStr,
    invoiceNumber,
    startTs: body.startTs || Date.now(),
  },
}];

