// Extract Claude's HTML and merge with invoice metadata.
const meta = $('Validate & Normalise').item.json;
const claudeResp = $json;

function extractText(node) {
  if (node && Array.isArray(node.content) && node.content[0] && typeof node.content[0].text === 'string') {
    return node.content[0].text;
  }
  throw new Error('Could not extract Claude HTML response');
}

let html = extractText(claudeResp).trim();
// Strip any accidental code fences
html = html.replace(/^```(?:html)?\s*/i, '').replace(/```\s*$/i, '').trim();

const servicesString = meta.lineItems.map(l => `${l.description} ($${l.amount.toFixed(2)})`).join('; ');

return [{
  json: {
    ...meta,
    invoiceHtml: html,
    servicesString,
  },
}];
